#!/usr/bin/env python3
"""Generate deploy/docker/docker-compose.yml from variants.json.

docker-compose.yml is a generated artifact: edit deploy/docker/variants.json and
re-run this script. `--check` verifies the committed file is up to date (used by
the test suite) and exits non-zero on drift.
"""

from __future__ import annotations

import argparse
import json
import sys
from pathlib import Path

HERE = Path(__file__).resolve().parent
VARIANTS_JSON = HERE / "variants.json"
COMPOSE_YML = HERE / "docker-compose.yml"

HEADER = """\
# GENERATED by deploy/docker/gen_compose.py from variants.json — DO NOT EDIT.
# Re-generate after editing variants.json:  python3 deploy/docker/gen_compose.py
#
# Local builds (mirrors run-docker.sh; same image/target/build-args):
#   QGC_UID=$(id -u) QGC_GID=$(id -g) docker compose -f deploy/docker/docker-compose.yml run --rm --build ubuntu
#   ... run --rm --build fedora Debug        # override build type
# Pass your uid/gid as QGC_UID/QGC_GID so build artifacts aren't root-owned.
"""


def _yaml_scalar(value: str) -> str:
    """Double-quote a scalar (JSON encoding is valid YAML and escapes specials)."""
    return json.dumps(value)


def _service(variant: dict) -> str:
    lines = [f"  {variant['id']}:"]
    lines.append("    build:")
    lines.append("      context: ../..")
    lines.append("      dockerfile: deploy/docker/Dockerfile")
    lines.append(f"      target: {variant['target']}")
    if variant["build_args"]:
        lines.append("      args:")
        for key, value in variant["build_args"].items():
            lines.append(f"        {key}: {_yaml_scalar(value)}")
    lines.append(f"    image: {variant['image']}")
    lines.append('    user: "${QGC_UID:-1000}:${QGC_GID:-1000}"')
    lines.append("    environment:")
    lines.append("      HOME: /tmp")
    lines.append('      CLEAN_BUILD: "${CLEAN_BUILD:-0}"')
    lines.append('      JOBS: "${JOBS:-}"')
    lines.append("    volumes:")
    lines.append("      - ../..:/project/source")
    lines.append("      - ../../build:/project/build")
    if variant["fuse"]:
        # FUSE mount for appimagetool/linuxdeploy (AppImage variants).
        lines.append("    cap_add: [SYS_ADMIN]")
        lines.append('    devices: ["/dev/fuse"]')
        lines.append('    security_opt: ["apparmor:unconfined"]')
    return "\n".join(lines)


def render() -> str:
    variants = json.loads(VARIANTS_JSON.read_text())["variants"]
    services = "\n".join(_service(v) for v in variants)
    return f"{HEADER}\nservices:\n{services}\n"


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--check", action="store_true", help="verify the committed file is current")
    args = parser.parse_args(argv)

    content = render()
    if args.check:
        current = COMPOSE_YML.read_text() if COMPOSE_YML.exists() else ""
        if current != content:
            sys.stderr.write(
                "docker-compose.yml is stale; run: python3 deploy/docker/gen_compose.py\n"
            )
            return 1
        return 0

    COMPOSE_YML.write_text(content)
    return 0


if __name__ == "__main__":
    sys.exit(main())
